  rate(theia_poll_results_total{
    job=~"$job",
    instance=~"$instance",
    outcome="failure",
    volatility_class=~"$volatility_class"
  }[$__rate_interval])
)
/
clamp_min(
  sum by (volatility_class) (
    rate(theia_poll_results_total{
      job=~"$job",
      instance=~"$instance",
      volatility_class=~"$volatility_class"
